from pages.base_page import BasePage
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
import page_objects.login_page as LoginLocators


class LoginPage(BasePage):
    """Login page object with authentication actions and validations"""

    def __init__(self, driver):
        super().__init__(driver)
        self.url = self.get_base_url() + "/login"

    # ── Navigation ────────────────────────────────────────────────────────────

    def navigate(self):
        """Navigate to login page"""
        self.driver.get(self.url)
        self.wait_for_page_load()

    # ── Actions ───────────────────────────────────────────────────────────────

    def enter_username(self, username):
        """Enter username/email in login form"""
        email_field = self.wait_for_element_visible(
            By.CSS_SELECTOR, LoginLocators.EMAIL_INPUT
        )
        email_field.clear()
        email_field.send_keys(username)

    def enter_password(self, password):
        """Enter password in login form"""
        password_field = self.wait_for_element_visible(
            By.CSS_SELECTOR, LoginLocators.PASSWORD_INPUT
        )
        password_field.clear()
        password_field.send_keys(password)

    def click_login_button(self):
        """Click login/submit button"""
        login_btn = self.wait_for_element_clickable(
            By.CSS_SELECTOR, LoginLocators.LOGIN_BUTTON
        )
        login_btn.click()
        self.wait_for_page_load()

    def login_with_credentials(self, username, password):
        """Complete login flow with provided credentials"""
        self.enter_username(username)
        self.enter_password(password)
        self.click_login_button()

    def login_as_role(self, role_name):
        """Login using credentials from test data by role name"""
        creds = self.get_credentials_by_role(role_name)
        self.login_with_credentials(creds['username'], creds['password'])

    def submit_empty_form(self):
        """Submit login form without filling any fields"""
        self.click_login_button()

    # ── Assertions ────────────────────────────────────────────────────────────

    def verify_login_page_loaded(self):
        """Verify login page displays with all required elements"""
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.EMAIL_INPUT
        ), "Email input field not visible"
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.PASSWORD_INPUT
        ), "Password input field not visible"
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.LOGIN_BUTTON
        ), "Login button not visible"
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.REGISTER_LINK
        ), "Register hyperlink not visible"

    def verify_login_successful(self):
        """Verify user successfully logged in and landed on dashboard/home"""
        WebDriverWait(self.driver, 10).until(
            EC.url_contains("/dashboard") or EC.url_contains("/home")
        )
        assert "/login" not in self.driver.current_url.lower(), "Still on login page after login attempt"

    def verify_login_failed_with_invalid_credentials(self):
        """Verify error message displays for invalid credentials"""
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.ERROR_MESSAGE
        ), "Error message not displayed for invalid credentials"
        error_text = self.get_element_text(By.CSS_SELECTOR, LoginLocators.ERROR_MESSAGE)
        assert "invalid" in error_text.lower() or "credentials" in error_text.lower(), \
            f"Expected invalid credentials error, got: {error_text}"

    def verify_required_field_error(self):
        """Verify required field validation error displays"""
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.EMPTY_FIELD_ERROR
        ), "Required field error not displayed"

    def verify_400_status_error(self):
        """Verify bad request error for empty/missing fields"""
        # For UI tests, validate error message presence
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.ERROR_MESSAGE
        ), "Error message not displayed for bad request"

    def verify_401_status_error(self):
        """Verify unauthorized error for authentication failure"""
        # For UI tests, validate authentication error message
        assert self.is_element_visible(
            By.CSS_SELECTOR, LoginLocators.INVALID_CREDENTIALS_MESSAGE
        ), "Authentication error message not displayed"
